-- functional_nutrient_catalog — DDL + seed (DB-first, fallback statico FUNCTIONAL_NUTRIENT_CATALOG).
-- Dato pubblico non per-utente: anon SELECT, service_role write. Idempotente (ON CONFLICT).
-- Loader server: lib/nutrition/functional-food-recommendations-db.ts
-- Loader client: lib/nutrition/functional-food-recommendations-client.ts

create table if not exists public.functional_nutrient_catalog (
  id text primary key,
  kind text not null,
  pathway_ids text[] not null default '{}',
  sort_order integer not null default 0,
  data jsonb not null,
  updated_at timestamptz not null default now()
);

create index if not exists functional_nutrient_catalog_kind_idx on public.functional_nutrient_catalog (kind);
create index if not exists functional_nutrient_catalog_pathways_idx on public.functional_nutrient_catalog using gin (pathway_ids);
create index if not exists functional_nutrient_catalog_sort_idx on public.functional_nutrient_catalog (sort_order);

alter table public.functional_nutrient_catalog enable row level security;

do $policy$
begin
  if not exists (select 1 from pg_policies where schemaname='public' and tablename='functional_nutrient_catalog' and policyname='functional_nutrient_catalog_read_anon') then
    create policy functional_nutrient_catalog_read_anon on public.functional_nutrient_catalog for select to anon, authenticated using (true);
  end if;
  if not exists (select 1 from pg_policies where schemaname='public' and tablename='functional_nutrient_catalog' and policyname='functional_nutrient_catalog_write_service') then
    create policy functional_nutrient_catalog_write_service on public.functional_nutrient_catalog for all to service_role using (true) with check (true);
  end if;
end
$policy$;

insert into public.functional_nutrient_catalog (id, kind, pathway_ids, sort_order, data)
select
  e->>'id',
  e->>'kind',
  coalesce((select array_agg(x) from jsonb_array_elements_text(e->'pathwayIds') as x), '{}'),
  (ord - 1)::int,
  e
from jsonb_array_elements($ffc$
